import bisect
n,q=map(int,input().split())
a=list(map(int,input().split()))
for _ in range(q):
    x=int(input())
    i=bisect.bisect_left(a,x)
    if i==0 or i>=len(a)+1:print('AUCUN')
    elif i<len(a) and a[i]==x and i>0:print(a[i-1])
    elif a[i-1]<x:print(a[i-1])
    else:print('AUCUN')

